// ─── Typeform Webhook Payload Parse ───
// Typeform form_id: wfbPF1am (Karakteristik Envanter Testi)

const body = $input.first().json.body || $input.first().json;
const formResponse = body.form_response || body;
const answers = formResponse.answers || [];
const variables = formResponse.variables || [];
const hidden = formResponse.hidden || {};

// ─── 1. Email bul ───
let email = '';
for (const ans of answers) {
  if (ans.type === 'email' || (ans.field && ans.field.type === 'email')) {
    email = (ans.email || '').toLowerCase().trim();
    break;
  }
}
if (!email && hidden.email) {
  email = hidden.email.toLowerCase().trim();
}

if (!email) {
  return [{ json: { error: true, message: 'Email bulunamadi', raw_keys: Object.keys(body) } }];
}

// ─── 1b. Ad-Soyad bul (name fallback icin) ───
let fullName = '';
for (const ans of answers) {
  const fieldType = ans.field && ans.field.type;
  const fieldRef = ans.field && (ans.field.ref || '');
  const fieldTitle = ((ans.field && ans.field.title) || '').toLowerCase();
  if (fieldType === 'short_text' && (fieldRef.includes('ad') || fieldRef.includes('name') || fieldTitle.includes('ad') || fieldTitle.includes('isim'))) {
    fullName = (ans.text || '').trim();
    if (fullName) break;
  }
}
if (!fullName && hidden.full_name) fullName = String(hidden.full_name).trim();

// ─── 2. Ilgi alanlarini bul ───
const disciplines = [];
const disciplineFields = ['Yazılım', 'Dijital Sanatlar', 'Dijital Pazarlama', 'Girişimcilik', 'Kişisel & Kariyer Gelişim'];
for (const ans of answers) {
  if (ans.type === 'choices' && ans.choices && ans.choices.labels) {
    for (const label of ans.choices.labels) {
      if (disciplineFields.includes(label)) disciplines.push(label);
    }
  }
  if (ans.type === 'choice' && ans.choice && ans.choice.label) {
    if (disciplineFields.includes(ans.choice.label)) disciplines.push(ans.choice.label);
  }
}

// ─── 3. Skorlari cikart (Typeform variables) ───
const scoreKeys = [
  'birlestirici','caliskan','canli','challenger','cozumcu',
  'gelecek_odakli','geleneksel','gozlemci','ilham_verici','inovatif',
  'kendinden_emin','mantikli','pratik','sistemli','tecrubeli',
  'titiz','tutkulu','yaratici'
];

const scores = {};
for (const v of variables) {
  if (v.type === 'number' && scoreKeys.includes(v.key)) {
    scores[v.key] = v.number || 0;
  }
}

// Hidden fields'tan da kontrol et (bazi formlar boyle gonderir)
for (const key of scoreKeys) {
  if (scores[key] === undefined && hidden[key] !== undefined) {
    scores[key] = Number(hidden[key]) || 0;
  }
}

const totalScore = Object.values(scores).reduce((sum, v) => sum + (Number(v) || 0), 0);

// ─── 4. Soru-cevaplari topla ───
const answersMap = {};
for (const ans of answers) {
  const title = (ans.field && ans.field.title) || '';
  if (!title || ans.type === 'email') continue;
  const value = ans.text || (ans.choice && ans.choice.label) || (ans.choices && ans.choices.labels && ans.choices.labels.join(', ')) || '';
  if (value) answersMap[title] = value;
}

return [{
  json: {
    error: false,
    email,
    full_name: fullName || null,
    test_type: 'karakteristik_envanter',
    disciplines,
    scores,
    total_score: totalScore,
    answers: answersMap,
    network_id: hidden.network_id || null,
    submitted_at: formResponse.submitted_at || new Date().toISOString(),
    response_type: 'completed',
    form_id: formResponse.form_id || 'wfbPF1am',
  }
}];

const res = $input.first().json;
const prevData = $('Typeform Verisini Ayikla').first().json;

return [{
  json: {
    status: res.success ? 'basarili' : 'hata',
    email: prevData.email,
    task_updated: res.task_updated || false,
    total_score: prevData.total_score,
    message: res.success 
      ? `${prevData.email} icin karakteristik envanter kaydedildi. Task guncellendi: ${res.task_updated}` 
      : `HATA: ${res.error}`,
  }
}];
